const QUESTIONS_CRISC_C4 = [
  { id:40701, domain:4, level:2, question:"What is the primary purpose of an enterprise architecture (EA) framework in managing IT risk?", options:["It aligns IT capabilities and assets with business objectives to reduce inconsistency and risk","It eliminates the need for any change management process within the organization entirely","It guarantees that all technology purchases will be delivered well under the planned budget in practice","It replaces the requirement for a formal disaster recovery plan across all business units"], correct:0, explanation:"EA aligns IT with business goals, exposing redundancy and risk. It does not eliminate change management, guarantee budgets, or replace disaster recovery planning." },
  { id:40702, domain:4, level:3, question:"A risk practitioner reviewing enterprise architecture notes undocumented point-to-point integrations. What is the GREATEST associated risk?", options:["A measurable reduction in the total electrical power consumed by the data center","Increased complexity that makes the impact of changes difficult to assess and control","An automatic improvement in the confidentiality of all data exchanged between systems","A guaranteed decrease in licensing costs charged by the software vendors involved"], correct:1, explanation:"Undocumented integrations raise complexity and change risk. They do not reduce power, improve confidentiality, or cut licensing costs." },
  { id:40703, domain:4, level:1, question:"Which artifact in enterprise architecture BEST helps identify single points of failure across systems?", options:["A quarterly marketing performance dashboard summarizing campaign conversion rates","An individual employee's annual performance appraisal and development objectives","A current-state technology and infrastructure dependency model of the environment","A vendor's standard end-user license agreement and acceptable use policy document"], correct:2, explanation:"A dependency model reveals systems whose failure cascades. Marketing dashboards, appraisals, and EULAs do not map technical dependencies." },
  { id:40704, domain:4, level:2, question:"What is the PRIMARY objective of a formal change management process?", options:["To make sure every proposed change is rejected unless the CEO personally approves it","To remove the need to test changes before they are deployed into production systems","To allow developers to deploy directly to production whenever they feel it is needed","To ensure changes are assessed, approved, and implemented in a controlled manner"], correct:3, explanation:"Change management controls assessment, approval, and implementation. It does not require CEO sign-off, skip testing, or permit uncontrolled deployment." },
  { id:40705, domain:4, level:3, question:"Emergency changes deployed without prior approval present which control concern?", options:["They may bypass risk assessment and testing, increasing the chance of unintended impact","They always cost significantly more money than equivalent standard planned changes do","They are inherently encrypted and therefore reduce the confidentiality risk of the data","They automatically improve user satisfaction scores recorded in the service desk system"], correct:0, explanation:"Emergency changes can skip assessment and testing, raising failure risk. They are not inherently costlier, encrypted, or satisfaction-boosting." },
  { id:40706, domain:4, level:2, question:"A change advisory board (CAB) is BEST described as a body that:", options:["Writes the application source code for every change that is requested by the users","Reviews and authorizes significant changes based on their risk and business impact","Performs the daily backup of all production databases and verifies restore success","Approves the annual marketing budget and allocates spending across the campaigns"], correct:1, explanation:"A CAB reviews and authorizes changes by risk and impact. It does not write code, run backups, or approve marketing budgets." },
  { id:40707, domain:4, level:3, question:"Which practice MOST reduces the risk of an unauthorized change reaching production?", options:["Allowing all team members to share one common administrator account credential set","Storing the production passwords in a plain spreadsheet on a shared network drive","Segregation of duties between those who develop and those who deploy the changes","Disabling logging on production servers to improve the overall system response times"], correct:2, explanation:"Segregation of duties prevents one person from developing and deploying unchecked. Shared accounts, plaintext passwords, and disabled logging worsen risk." },
  { id:40708, domain:4, level:1, question:"What does a configuration management database (CMDB) primarily provide?", options:["A real-time stock trading platform used by the corporate treasury department daily","A repository solely for storing scanned copies of employee expense receipts and claims","A messaging system used to broadcast emergency alerts to all staff mobile phones at once","A record of configuration items and their relationships to support change decisions"], correct:3, explanation:"A CMDB records configuration items and relationships, aiding impact analysis. It is not a trading platform, receipt store, or alerting system." },
  { id:40709, domain:4, level:2, question:"Configuration drift refers to which condition in managed systems?", options:["Gradual divergence of a system's actual configuration from its approved baseline","The planned and documented migration of a workload from one cloud region to another","The scheduled rotation of cryptographic keys according to the organization's policy","The deliberate increase of network bandwidth to support a seasonal traffic spike event"], correct:0, explanation:"Drift is unplanned divergence from baseline. The other options describe planned, controlled activities, not uncontrolled deviation." },
  { id:40710, domain:4, level:3, question:"The PRIMARY goal of release management is to achieve what outcome?", options:["Determine the annual compensation and bonus structure for all the software engineers","Plan, schedule, and control the movement of releases to test and live environments","Negotiate the licensing terms and renewal dates with every third-party software vendor","Decide which physical workstation each developer will be assigned within the office space"], correct:1, explanation:"Release management controls movement of releases across environments. It does not set salaries, negotiate licenses, or assign workstations." },
  { id:40711, domain:4, level:2, question:"Why is timely patch management important for managing IT risk?", options:["It permanently removes the need for any antivirus or endpoint protection software tools","It guarantees that no new vulnerabilities will ever be discovered in the software again","It reduces the window of exposure to known vulnerabilities that attackers can exploit","It automatically encrypts all of the data stored on the patched system's local drives"], correct:2, explanation:"Patching shrinks the exposure window for known flaws. It does not replace antivirus, prevent future vulnerabilities, or encrypt data." },
  { id:40712, domain:4, level:3, question:"Before deploying a critical patch to production, the BEST practice is to do what?", options:["Deploy directly to all production systems at once to minimize the total elapsed time","Wait until the vendor releases at least three successive newer patch versions first","Disable all monitoring during deployment so that alerts do not distract the team members","Test the patch in a representative non-production environment to assess its impact"], correct:3, explanation:"Testing in a representative environment limits production disruption. Direct mass deployment, indefinite waiting, and disabling monitoring all add risk." },
  { id:40713, domain:4, level:1, question:"A high-severity vulnerability has a vendor patch available, but patching requires downtime. The risk practitioner should FIRST do what?", options:["Assess the risk of exploitation against the business impact of the required downtime","Immediately ignore the vulnerability because any downtime is never acceptable at all","Publicly disclose the vulnerability details on social media to warn other companies","Remove the affected system from the asset inventory to avoid having to track the issue"], correct:0, explanation:"Balancing exploitation risk against downtime impact informs the decision. Ignoring, public disclosure, and hiding the asset are inappropriate." },
  { id:40714, domain:4, level:2, question:"From a risk perspective, the MOST important reason to involve risk management early in a project is what?", options:["To ensure the project manager receives a larger performance bonus at project completion","To identify and address risks while changes are still inexpensive and feasible to make","To guarantee that the project will finish ahead of schedule regardless of its full scope","To avoid the need to ever produce any formal project documentation or status reporting"], correct:1, explanation:"Early risk involvement addresses issues cheaply. It does not relate to bonuses, guarantee schedules, or eliminate documentation." },
  { id:40715, domain:4, level:3, question:"Scope creep in a project MOST directly increases the risk of which outcome?", options:["Improved data center cooling efficiency across the organization's various server rooms","Stronger encryption being applied automatically to all of the project communications","Cost overruns and schedule delays due to uncontrolled expansion of the requirements","Reduced dependency on any external vendors or third-party service providers involved"], correct:2, explanation:"Scope creep drives cost and schedule risk. It is unrelated to cooling, encryption, or vendor dependence." },
  { id:40716, domain:4, level:2, question:"What does Recovery Time Objective (RTO) define for a business process?", options:["The maximum amount of data, measured in time, that can be lost during an outage event","The total monetary value of the hardware located within the primary corporate data center","The number of staff required to physically guard the alternate recovery facility site","The maximum acceptable time to restore a process or system after a disruption occurs"], correct:3, explanation:"RTO is the target restoration time. RPO concerns acceptable data loss; the others describe asset value and staffing, not RTO." },
  { id:40717, domain:4, level:3, question:"What does Recovery Point Objective (RPO) define for a business process?", options:["The maximum acceptable amount of data loss measured as a period of elapsed time","The maximum acceptable elapsed time before a business process must be restored fully","The minimum network bandwidth required between the primary and the secondary processing sites","The total number of users permitted to log in to the recovery system simultaneously at once"], correct:0, explanation:"RPO is tolerable data loss in time. RTO is the restoration time target; the others are unrelated network and capacity metrics." },
  { id:40718, domain:4, level:1, question:"A business impact analysis (BIA) PRIMARILY helps an organization to do what?", options:["Configure the firewall rules that govern inbound and outbound network traffic flows","Identify critical processes and the impact of their disruption over time periods","Select the programming language used to build the organization's core applications","Calculate the annual depreciation of all owned office furniture and fixtures owned"], correct:1, explanation:"A BIA identifies critical processes and disruption impact, informing RTO/RPO. It does not configure firewalls, pick languages, or depreciate furniture." },
  { id:40719, domain:4, level:2, question:"Which recovery site can resume operations the FASTEST after a disaster?", options:["A cold site providing only physical space, power, and network connectivity initially","A warm site with the hardware installed but requiring data restoration before being used","A hot site with fully configured systems and current data ready for immediate use","A reciprocal agreement to share a partner organization's facilities during a crisis event"], correct:2, explanation:"A hot site is fully ready, enabling fastest recovery. Cold and warm sites and reciprocal agreements require more setup time." },
  { id:40720, domain:4, level:3, question:"If an organization has an RPO of four hours, backups should occur how often?", options:["Once per calendar year during a scheduled maintenance weekend in December only","Only after a disaster has already been declared by the crisis management team members","Exclusively when storage utilization exceeds ninety-five percent of total capacity","At least every four hours to limit the potential data loss to within that window"], correct:3, explanation:"Backups at least every RPO interval limit data loss to that window. Annual, post-disaster, or capacity-triggered backups cannot meet a four-hour RPO." },
  { id:40721, domain:4, level:2, question:"The PRIMARY reason to test a disaster recovery plan regularly is what?", options:["To validate that the plan works and identify gaps before an actual disaster occurs","To satisfy a personal preference of the IT manager with no underlying business need","To provide an opportunity for staff to take an extended paid day away from normal work","To increase the storage consumed by backup media to justify buying more new hardware"], correct:0, explanation:"DR testing validates the plan and surfaces gaps proactively. The other options are not legitimate reasons to test." },
  { id:40722, domain:4, level:3, question:"The data lifecycle stage at which the risk of disclosure from improper disposal is HIGHEST is which?", options:["Creation, when the data has not yet been written to any storage medium at all so far","Destruction, when media must be sanitized to prevent recovery of the residual data","Classification, which only assigns a sensitivity label and stores no actual content yet","Transmission, where the data exists only momentarily on the network while in transit"], correct:1, explanation:"Improper destruction can leave recoverable data, the disclosure risk in question. Creation, classification, and transmission pose different risks." },
  { id:40723, domain:4, level:1, question:"Data classification PRIMARILY supports risk management by doing what?", options:["Reducing the physical weight of the storage devices used in the data center racks","Guaranteeing that all of the data will be retained permanently and never be deleted in practice","Ensuring controls are applied commensurate with the sensitivity of the data involved","Eliminating the need to encrypt any of the data regardless of its sensitivity level"], correct:2, explanation:"Classification matches control strength to sensitivity. It does not affect device weight, mandate permanent retention, or remove encryption needs." },
  { id:40724, domain:4, level:2, question:"A data retention policy MOST directly helps reduce risk by doing what?", options:["Forcing every employee to memorize the full contents of the corporate database tables","Guaranteeing that storage costs will rise predictably every single fiscal quarter ahead","Allowing any user to delete any record at any time without any approval needed at all","Ensuring data is kept only as long as it is required and then disposed of properly"], correct:3, explanation:"Retention policies limit data held to what is needed and govern disposal. They do not require memorization, raise costs, or permit uncontrolled deletion." },
  { id:40725, domain:4, level:3, question:"Data masking is MOST appropriate to reduce risk in which situation?", options:["Production data must be used in test environments without exposing the sensitive values","A system requires the original sensitive values to perform its financial calculations","Encryption keys need to be generated for a newly provisioned production database server","Network packets must be routed between two separate segments of the corporate intranet"], correct:0, explanation:"Masking protects sensitive values in non-production use. It is unsuitable when real values are needed, and is unrelated to key generation or routing." },
  { id:40726, domain:4, level:2, question:"From a risk standpoint, end-of-life (EOL) hardware is a concern PRIMARILY because of what?", options:["It consumes slightly less rack space than newer replacement equipment usually does","The vendor no longer provides security updates, leaving vulnerabilities left unpatched","It is always physically lighter and therefore easier for technicians to move around","It automatically uses stronger encryption than any of the currently supported hardware"], correct:1, explanation:"EOL hardware loses vendor security updates, leaving flaws unpatched. The other statements are irrelevant or false regarding EOL risk." },
  { id:40727, domain:4, level:3, question:"A network firewall's PRIMARY function is to do what?", options:["Permanently encrypt every file that is stored on the connected end-user workstations","Generate and rotate all of the organization's cryptographic certificate signing keys","Control traffic between networks based on a defined set of security rules and policies","Physically prevent unauthorized people from entering the secured server room facility in practice"], correct:2, explanation:"A firewall filters traffic by rules. It does not encrypt files, manage certificates, or provide physical access control." },
  { id:40728, domain:4, level:1, question:"Network segmentation reduces risk PRIMARILY by doing what?", options:["Increasing the raw clock speed of the central processing units in each of the servers","Removing the need to apply any security patches to systems within a given segment area","Guaranteeing that no malware can ever enter any part of the corporate network at all","Limiting an attacker's lateral movement and containing the scope of a security breach"], correct:3, explanation:"Segmentation contains breaches and limits lateral movement. It does not boost CPU speed, remove patching needs, or guarantee total immunity." },
  { id:40729, domain:4, level:2, question:"Integrating security requirements early in the SDLC is important because of what?", options:["Addressing security in the design phase is cheaper and more effective than fixing later","It allows the testing phase to be skipped entirely to save the project schedule time","It removes the requirement to ever document any of the system's functional needs at all","It ensures the application will require absolutely no maintenance after it is deployed"], correct:0, explanation:"Early security design is cheaper and more effective than late remediation. It does not justify skipping testing, documentation, or maintenance." },
  { id:40730, domain:4, level:3, question:"In the SDLC, the PRIMARY purpose of the requirements phase is to do what?", options:["Decommission the legacy hardware that the new system is intended to replace soon after","Define what the system must do, including its necessary security and control needs","Train the end users on how to operate the system once it is fully in production use","Write the final production source code and deploy it directly to the live servers"], correct:1, explanation:"Requirements define system needs, including controls. Decommissioning, training, and coding occur in other phases." },
  { id:40731, domain:4, level:2, question:"Performing security testing only after deployment rather than during the SDLC MOST increases the risk of what?", options:["Reduced electricity consumption by the development workstations during the project in practice","Faster onboarding of new developers joining the project team in the later phases","Costly rework and undetected vulnerabilities reaching the production environment late","Improved accuracy of the marketing department's quarterly revenue forecast numbers"], correct:2, explanation:"Late-only testing raises rework cost and lets flaws reach production. The other options are unrelated to test timing." },
  { id:40732, domain:4, level:3, question:"In a cloud Infrastructure-as-a-Service (IaaS) model, the customer is GENERALLY responsible for what?", options:["Maintaining the physical security of the cloud provider's many global data centers","Replacing failed hard drives within the provider's underlying storage hardware units","Designing the provider's internal hypervisor and host operating system patch process","Securing the operating systems, applications, and data they deploy on the service"], correct:3, explanation:"Under shared responsibility, IaaS customers secure their OS, apps, and data. The provider handles physical, hardware, and hypervisor layers." },
  { id:40733, domain:4, level:1, question:"A PRIMARY risk introduced by Internet of Things (IoT) devices is what?", options:["They often ship with weak default credentials and limited capacity for security updates","They always include enterprise-grade hardware security modules by default in every unit","They are universally exempt from any form of network-based attack due to their design","They automatically encrypt all of their communications with quantum-resistant algorithms"], correct:0, explanation:"Many IoT devices have weak defaults and poor update support. They do not universally include HSMs, immunity, or quantum-resistant crypto." },
  { id:40734, domain:4, level:2, question:"A key risk when adopting AI or machine learning systems is which of the following?", options:["The complete elimination of any need for human oversight of the automated decisions","Biased or poor-quality training data leading to inaccurate or unfair model outcomes","A guarantee that the model's outputs will always be correct in every single situation","The automatic removal of all privacy obligations for the data used to train the model"], correct:1, explanation:"Poor or biased training data produces flawed outcomes. AI does not remove oversight needs, guarantee correctness, or erase privacy duties." },
  { id:40735, domain:4, level:3, question:"Virtualization introduces which specific risk that physical servers do not?", options:["Virtual machines can never be backed up because they have no underlying disk files","Each virtual machine requires its own separate physical power supply unit to operate in practice","A hypervisor compromise could affect all of the virtual machines running on that host","Virtual machines are entirely immune to operating system vulnerabilities by nature"], correct:2, explanation:"A compromised hypervisor endangers all hosted VMs. VMs are file-based, share physical hardware, and still have OS vulnerabilities." },
  { id:40736, domain:4, level:2, question:"When using a public cloud provider, vendor lock-in is a risk because of what?", options:["It physically prevents the organization from ever signing any other vendor contract","It automatically guarantees that the provider's prices will decrease every single year","It ensures the organization's data is always encrypted with keys it solely controls","Proprietary services can make migrating to another provider costly and very difficult"], correct:3, explanation:"Proprietary dependencies raise migration cost and difficulty. Lock-in does not bar new contracts, lower prices, or guarantee customer-held keys." },
  { id:40737, domain:4, level:3, question:"The CIA triad in information security stands for which three properties?", options:["Confidentiality, integrity, and availability of the information and the systems involved","Control, inspection, and authorization of all of the employee physical access badges","Compliance, insurance, and accounting for the organization's many financial records","Containment, isolation, and analysis used during an incident response process activity in practice"], correct:0, explanation:"The CIA triad is confidentiality, integrity, and availability. The other phrases are plausible-sounding but incorrect expansions." },
  { id:40738, domain:4, level:1, question:"Defense in depth is BEST described as which approach?", options:["Relying on a single very strong perimeter firewall as the only protective control used","Layering multiple independent controls so failure of one does not expose the asset","Encrypting data once at rest and assuming no other control is ever required again at all","Granting all of the users full administrative rights to simplify support and maintenance"], correct:1, explanation:"Defense in depth layers controls for redundancy. A single firewall, lone encryption, or universal admin rights contradict the concept." },
  { id:40739, domain:4, level:2, question:"Which principle states that users should be granted only the access necessary for their duties?", options:["Maximum availability, which grants broad access to keep all the systems fully usable","Open by default, which permits access unless a rule explicitly denies it to the user","Least privilege, which minimizes the access rights that are assigned to each user","Shared accountability, which assigns one single login to an entire department team"], correct:2, explanation:"Least privilege limits access to what is needed. The other options describe practices that increase, not reduce, access risk." },
  { id:40740, domain:4, level:3, question:"The PRIMARY goal of a security awareness program is to do what?", options:["Replace all technical security controls so that they no longer need to be maintained","Ensure every employee can personally write secure application source code on a daily basis","Guarantee that no phishing email will ever reach any employee's inbox ever again at all","Reduce risk from human error by changing employee behavior and increasing knowledge"], correct:3, explanation:"Awareness programs reduce human-error risk through behavior change. They do not replace technical controls, teach all coding, or block all phishing." },
  { id:40741, domain:4, level:2, question:"A simulated phishing campaign is MOST useful to an organization because it does what?", options:["Measures user susceptibility and reinforces training in a controlled and safe manner","Permanently removes all malicious email from arriving at the mail gateway entirely","Eliminates the requirement to deploy any email filtering technology whatsoever ever in practice","Guarantees that no employee will ever click on a real malicious link in the future"], correct:0, explanation:"Simulated phishing measures susceptibility and reinforces learning safely. It does not block real email, replace filtering, or guarantee no future clicks." },
  { id:40742, domain:4, level:3, question:"Data minimization, a key privacy principle, requires that an organization do what?", options:["Gather as much personal data as possible in case it proves to be useful much later on","Collect and retain only the personal data necessary for a clearly specified purpose","Share all of the collected personal data freely with any partner that requests access","Retain every record indefinitely to avoid ever having to make a deletion decision later"], correct:1, explanation:"Data minimization limits collection and retention to what is necessary. The other options describe excessive collection, sharing, or retention." },
  { id:40743, domain:4, level:1, question:"Under many privacy regulations, the lawful basis MOST associated with individual control of data is which?", options:["Convenience, where the organization processes data whenever it is simplest to do so","Profitability, where data is processed only when it directly increases the revenue","Consent, where the individual affirmatively agrees to the specified data processing","Availability, where data is processed because the system happens to be online then"], correct:2, explanation:"Consent is a recognized lawful basis giving individuals control. The other terms are not valid lawful bases under privacy law." },
  { id:40744, domain:4, level:2, question:"A privacy impact assessment (PIA) is PRIMARILY used to do what?", options:["Calculate the depreciation schedule for the servers hosting the new application code","Determine the marketing budget allocated to promoting the new system to its customers","Select the brand of physical locks installed on the data center entrance doors used","Identify and reduce privacy risks before a new system or process is implemented"], correct:3, explanation:"A PIA identifies and mitigates privacy risk proactively. It is unrelated to depreciation, marketing budgets, or physical locks." },
  { id:40745, domain:4, level:3, question:"Multi-factor authentication (MFA) reduces risk PRIMARILY by doing what?", options:["Requiring multiple independent factors, so a stolen password alone is not sufficient","Encrypting all data stored on the server so no password is ever required to log in","Allowing users to reuse the same single password across every corporate system used","Eliminating the need to ever review or revoke user access rights at any point in future"], correct:0, explanation:"MFA requires multiple factors, so a stolen password is not enough. It is not an encryption mechanism and does not enable reuse or end access reviews." },
  { id:40746, domain:4, level:2, question:"Role-based access control (RBAC) assigns permissions based on what?", options:["The physical floor of the building on which the user's desk happens to be located in practice","A user's job role, which simplifies administration and supports least privilege use","The alphabetical order of each user's surname within the corporate user directory","The personal preference of each user regarding which systems they wish to access"], correct:1, explanation:"RBAC ties permissions to job roles, aiding least privilege. It is not based on desk location, surname order, or personal preference." },
  { id:40747, domain:4, level:3, question:"A periodic user access review (recertification) is performed PRIMARILY to do what?", options:["Increase the number of privileged accounts in order to speed up the support tickets","Permanently lock all of the accounts so that no user can log in until the next review","Detect and remove access that is no longer appropriate for each individual user","Replace the need for any logging or monitoring of the user activity on the systems"], correct:2, explanation:"Access reviews detect and remove inappropriate access. They do not add privileges, lock all accounts, or replace logging." },
  { id:40748, domain:4, level:1, question:"The risk of orphan accounts that remain active after staff depart is BEST mitigated by what?", options:["Allowing departed employees to keep their accounts for sentimental record purposes","Sharing the departed employee's account with the rest of their former team members","Increasing the password length requirement for all of the newly created accounts only","A timely de-provisioning process that is tied to employee termination workflows"], correct:3, explanation:"Prompt de-provisioning on termination removes orphan accounts. Keeping, sharing, or merely changing password rules does not address the root cause." },
  { id:40749, domain:4, level:2, question:"Privileged access management (PAM) solutions reduce risk MAINLY by doing what?", options:["Controlling, monitoring, and recording the use of the highly privileged accounts","Granting every standard user permanent administrator rights for added convenience","Removing the need to authenticate when accessing the most sensitive systems at all","Disabling audit logging on administrator sessions to improve their performance levels"], correct:0, explanation:"PAM controls, monitors, and records privileged use. It does not grant universal admin, remove authentication, or disable logging." },
  { id:40750, domain:4, level:3, question:"Symmetric encryption differs from asymmetric encryption in that symmetric encryption does what?", options:["Uses a public key to encrypt and a separate private key to decrypt the data fully","Uses the same secret key for both the encryption and the decryption of the data","Requires no key at all because the algorithm itself keeps the data confidential","Can only ever be used to verify digital signatures and never to protect any data"], correct:1, explanation:"Symmetric encryption uses one shared key. Public/private key pairs describe asymmetric; keyless and signature-only descriptions are incorrect." },
  { id:40751, domain:4, level:2, question:"Encrypting data at rest PRIMARILY protects against which risk?", options:["Denial-of-service attacks that flood the network with excessive traffic volume","Phishing emails that trick users into revealing their login credentials willingly","Unauthorized disclosure if the storage media or backups are lost or stolen","Physical theft of the office furniture surrounding the storage equipment racks"], correct:2, explanation:"Encryption at rest protects against disclosure from lost or stolen media. It does not stop DoS, phishing, or furniture theft." },
  { id:40752, domain:4, level:3, question:"A digital signature primarily provides which security properties?", options:["Confidentiality, by hiding the message contents from all of the unintended readers in practice","Availability, by guaranteeing that the message can always be retrieved on demand","Anonymity, by ensuring the sender's identity can never be determined by anyone","Integrity and authenticity, confirming the message is unchanged and from the signer"], correct:3, explanation:"Digital signatures provide integrity and authenticity. Confidentiality requires encryption; signatures do not ensure availability or anonymity." },
  { id:40753, domain:4, level:1, question:"The risk of weak or outdated cryptographic algorithms is which of the following?", options:["They may be broken by attackers, undermining the confidentiality they were to provide","They always consume so much processing power that systems will immediately fail to start","They automatically alert the security team whenever any encrypted data is accessed once","They permanently prevent legitimate users from ever decrypting their own valid data"], correct:0, explanation:"Weak algorithms can be broken, undermining confidentiality. They do not block startup, generate access alerts, or bar legitimate decryption." },
  { id:40754, domain:4, level:2, question:"An intrusion detection system (IDS) PRIMARILY does what?", options:["Physically blocks all unauthorized personnel from entering the data center floor area","Monitors network or system activity and alerts on suspicious or malicious patterns","Automatically writes patches for any vulnerability that it happens to discover anywhere","Encrypts all of the data transmitted between the organization's branch office locations"], correct:1, explanation:"An IDS monitors and alerts on suspicious activity. It does not control physical access, write patches, or encrypt traffic." },
  { id:40755, domain:4, level:3, question:"The main difference between an IDS and an IPS is that an IPS can do what?", options:["Only generate reports at the end of each month rather than in real time at all ever","Function exclusively on wireless networks and never on any wired connection types","Actively block or prevent detected malicious traffic, not merely alert on it later","Replace the need for any firewall, encryption, or access control on the whole network"], correct:2, explanation:"An IPS can block malicious traffic, while an IDS only alerts. The other statements misdescribe IPS capabilities." },
  { id:40756, domain:4, level:2, question:"A virtual private network (VPN) reduces risk for remote access PRIMARILY by doing what?", options:["Increasing the physical distance allowed between a laptop and its wireless router unit","Removing the requirement for remote users to authenticate before connecting at all","Guaranteeing unlimited internet bandwidth to every remote employee at all times daily","Encrypting traffic between the remote user and the corporate network over the internet"], correct:3, explanation:"A VPN encrypts remote traffic over untrusted networks. It does not extend Wi-Fi range, remove authentication, or guarantee bandwidth." },
  { id:40757, domain:4, level:3, question:"A demilitarized zone (DMZ) in network architecture is used to do what?", options:["Host internet-facing services in a segment isolated from the internal trusted network","Store the only copy of all backup tapes for the entire organization's many systems in practice","Provide a physical break room located between two secured office building wings","Run the payroll database directly on the public internet for easier remote access"], correct:0, explanation:"A DMZ isolates internet-facing services from the internal network. It is not a backup vault, break room, or place for sensitive databases." },
  { id:40758, domain:4, level:1, question:"A security information and event management (SIEM) system PRIMARILY helps by doing what?", options:["Physically destroying decommissioned hard drives to prevent any later data recovery","Aggregating and correlating logs to detect and investigate potential security incidents","Negotiating cyber insurance premiums with the organization's chosen underwriters","Automatically purchasing replacement hardware whenever a server component fails on it in practice"], correct:1, explanation:"A SIEM aggregates and correlates logs for detection and investigation. It does not destroy media, negotiate insurance, or buy hardware." },
  { id:40759, domain:4, level:2, question:"The PRIMARY value of centralized logging for risk management is which of the following?", options:["It reduces the total number of employees that the organization needs to employ daily","It guarantees that no system will ever experience an outage or a performance issue","It supports detection, investigation, and accountability across the multiple systems","It allows administrators to safely share a single password across all of the systems"], correct:2, explanation:"Centralized logging aids detection, investigation, and accountability. It does not cut staff, prevent outages, or justify shared passwords." },
  { id:40760, domain:4, level:3, question:"Why should audit logs be protected from unauthorized modification?", options:["To reduce the amount of disk storage that the logs consume on the server over time","To allow any user to freely edit the logs whenever they believe an error occurred","To ensure the logs can be deleted automatically before any incident is investigated","To preserve their integrity so they remain reliable evidence of the system activity"], correct:3, explanation:"Protecting log integrity keeps them reliable as evidence. Reducing storage, free editing, and pre-incident deletion all undermine that goal." },
  { id:40761, domain:4, level:2, question:"The FIRST priority during the containment phase of incident response is to do what?", options:["Limit the spread and impact of the incident before it affects even more systems","Immediately issue a press release describing every technical detail to the public","Permanently delete all affected systems before any evidence can be collected at all","Assign blame to a specific individual employee before the facts have been gathered"], correct:0, explanation:"Containment limits spread and impact first. Premature public disclosure, evidence destruction, and blame-assignment are inappropriate." },
  { id:40762, domain:4, level:3, question:"Preserving evidence during incident response is important PRIMARILY because it does what?", options:["It increases the available free disk space on the affected production servers used","It supports root cause analysis and any subsequent legal or disciplinary action taken","It guarantees that the same type of incident can never possibly happen again ever","It removes the organization's obligation to notify any of the affected data subjects in practice"], correct:1, explanation:"Evidence preservation supports root cause analysis and legal action. It does not free disk space, prevent recurrence, or remove notification duties." },
  { id:40763, domain:4, level:1, question:"An incident response plan should be tested periodically MAINLY to do what?", options:["Increase the number of incidents the organization experiences each calendar year","Provide the legal team with billable hours that can be charged back to the clients","Ensure roles, procedures, and communications work effectively before a real incident","Replace the requirement to maintain any preventive security controls at all anymore in practice"], correct:2, explanation:"Testing validates roles, procedures, and communications. It does not increase incidents, generate billing, or replace preventive controls." },
  { id:40764, domain:4, level:2, question:"Which is the BEST first action when a workstation is suspected of active malware infection?", options:["Continue using the workstation normally so as not to alert the attacker who is present","Forward the suspicious files to all colleagues to ask whether they look harmful or not","Immediately reformat the drive before any investigation or evidence collection at all","Isolate the workstation from the network to prevent the malware from spreading further"], correct:3, explanation:"Isolation prevents spread while preserving the system for analysis. Continued use, forwarding files, and immediate reformatting all increase risk." },
  { id:40765, domain:4, level:3, question:"A vulnerability assessment differs from a penetration test in that an assessment does what?", options:["Identifies and reports weaknesses, typically without actively exploiting any of them","Always results in permanent damage to every system that is included within the scope","Can only be performed on physical building security and never on any IT systems at all","Guarantees the discovery of every single weakness with absolutely no exceptions ever"], correct:0, explanation:"A vulnerability assessment identifies weaknesses without exploiting them; pen tests exploit. It does not cause damage, exclude IT, or guarantee completeness." },
  { id:40766, domain:4, level:2, question:"Prioritizing remediation of vulnerabilities should be based PRIMARILY on what?", options:["The alphabetical order of the host names of the affected systems in the inventory","The risk each vulnerability poses, considering its likelihood and potential impact","Whichever vulnerability was reported most recently regardless of its severity level","The personal preference of whichever administrator is on duty that particular day"], correct:1, explanation:"Risk-based prioritization weighs likelihood and impact. Alphabetical order, recency alone, and personal preference are not sound bases." },
  { id:40767, domain:4, level:3, question:"A threat is BEST defined as which of the following?", options:["A control implemented specifically to reduce the likelihood of a loss event occurring","The monetary value that is assigned to an information asset within the organization","A potential cause of an unwanted incident that may harm a system or the organization","A documented agreement between an organization and one of its external providers"], correct:2, explanation:"A threat is a potential cause of an unwanted incident. The other options describe a control, asset value, and an agreement, respectively." },
  { id:40768, domain:4, level:1, question:"Zero-day vulnerabilities are particularly dangerous because of what?", options:["They can only ever be exploited exactly once and then become harmless forever after","They are always automatically blocked by any standard signature-based antivirus tool in practice","They only affect systems that have already been fully decommissioned and removed","No patch is yet available, so attackers can exploit them before any fix exists at all"], correct:3, explanation:"Zero-days lack an available patch, enabling exploitation before remediation. The other statements misstate how zero-days behave." },
  { id:40769, domain:4, level:2, question:"Threat intelligence MOST directly supports risk management by doing what?", options:["Informing decisions with current information about relevant threats and their tactics","Eliminating the need to apply any patches to the organization's software systems","Guaranteeing that the organization will never be targeted by any attacker at all ever","Automatically remediating every vulnerability the moment that it is first discovered"], correct:0, explanation:"Threat intelligence informs decisions about relevant threats. It does not remove patching needs, guarantee immunity, or auto-remediate flaws." },
  { id:40770, domain:4, level:3, question:"Which control BEST addresses the risk of data loss from a failed hard drive?", options:["Increasing the monitor brightness on the affected user's primary workstation display","Maintaining regular backups that are stored on separate and reliable media types","Renaming the database files so that they are harder for an attacker to locate quickly","Reducing the office air conditioning to keep the server cabinets running much cooler"], correct:1, explanation:"Backups on separate media restore data after drive failure. Brightness, renaming, and cooling do not protect against data loss from failure." },
  { id:40771, domain:4, level:2, question:"A cold recovery site is BEST characterized by which description?", options:["Fully operational systems with live data ready to take over the load instantly","Hardware installed and only needing the recent data to be restored quickly first","Having space and utilities but lacking ready hardware and current restored data","A mobile trailer that automatically follows the staff to any chosen location"], correct:2, explanation:"A cold site has space and utilities but no ready hardware or data. The other options describe hot, warm, and a fictional arrangement." },
  { id:40772, domain:4, level:3, question:"The MOST important reason to maintain an accurate asset inventory is to do what?", options:["Decide which employees receive the largest annual performance bonuses each year","Increase the resale value of the office furniture located near the server equipment in practice","Reduce the total number of network cables required across the whole office building","Ensure all assets are accounted for and protected by the appropriate set of controls"], correct:3, explanation:"An accurate inventory ensures assets are protected by controls. It is unrelated to bonuses, furniture value, or cabling." },
  { id:40773, domain:4, level:1, question:"Capacity management helps reduce which type of risk in IT operations?", options:["Availability risk from systems becoming overloaded and then unable to perform well","Confidentiality risk from encryption keys being shared among unauthorized users","Legal risk from failing to register a corporate trademark in time before a deadline","Reputational risk from a poorly designed company logo placed on the public website"], correct:0, explanation:"Capacity management prevents overload, an availability concern. It does not address key sharing, trademarks, or logos." },
  { id:40774, domain:4, level:2, question:"A service level agreement (SLA) with a cloud provider MOST helps manage risk by doing what?", options:["Guaranteeing the provider can never suffer any outage under any circumstance at all","Defining measurable expectations such as availability and the support response times","Transferring all legal liability for any data breaches entirely to the paying customer","Eliminating the customer's need to implement any of its own internal security controls"], correct:1, explanation:"An SLA defines measurable expectations. It does not guarantee zero outages, shift all liability, or remove customer control duties." },
  { id:40775, domain:4, level:3, question:"The PRIMARY risk of using unsupported (end-of-life) software is which of the following?", options:["The software becomes physically heavier and much harder to install on the servers","The software automatically deletes itself from every system after one full year passes","Lack of security updates leaves the known vulnerabilities permanently left unpatched","Users are legally required to immediately purchase competing products instead at once"], correct:2, explanation:"Unsupported software stops receiving security updates. The other statements are false or irrelevant." },
  { id:40776, domain:4, level:2, question:"Tokenization reduces risk by doing what?", options:["Permanently increasing the size of the database to accommodate the larger records","Sharing the original sensitive data with every application that happens to request it","Storing all of the sensitive data in plain text within a single central spreadsheet","Replacing sensitive data with non-sensitive tokens that have no exploitable value"], correct:3, explanation:"Tokenization substitutes tokens for sensitive data, reducing exposure. The other options increase or do not address risk." },
  { id:40777, domain:4, level:3, question:"A warm recovery site typically requires which step before reaching full operation?", options:["Restoration of the recent data onto the pre-installed hardware already at the site","Construction of an entirely new building from the ground up before any use at all in practice","Negotiation of a completely new internet service contract from scratch each time","Manufacturing of custom server hardware that does not yet exist anywhere on earth"], correct:0, explanation:"A warm site has hardware but needs data restored. The other steps describe far longer, unnecessary efforts." },
  { id:40778, domain:4, level:1, question:"When classifying a system's criticality, the BEST input to use is which of the following?", options:["The brand and the color of the physical server chassis that the system runs on","The business impact of the system's unavailability on the organization's key processes","The number of years the lead administrator has worked at the company so far","The alphabetical position of the system's name within the overall inventory list in practice"], correct:1, explanation:"Criticality reflects business impact of unavailability. Chassis brand, tenure, and naming order are irrelevant." },
  { id:40779, domain:4, level:2, question:"Network access control (NAC) reduces risk by doing what?", options:["Guaranteeing that all of the connected devices will run at maximum possible speed","Removing the requirement for any device to ever install any antivirus software at all","Ensuring that only compliant and authorized devices can connect to the network","Automatically paying the internet service provider's monthly network access invoice"], correct:2, explanation:"NAC enforces device compliance and authorization. It does not boost speed, remove antivirus needs, or pay invoices." },
  { id:40780, domain:4, level:3, question:"A honeypot is used PRIMARILY for which purpose?", options:["To store the organization's only production database for high availability purposes","To provide the fastest possible internet connection to the executive workstations","To serve as the primary email server for all of the company's daily mail traffic","To attract and study attacker activity within an isolated and monitored environment"], correct:3, explanation:"A honeypot lures and studies attackers in isolation. It is never used to host production data or critical services." },
  { id:40781, domain:4, level:2, question:"The risk of shadow IT (unsanctioned technology) is GREATEST because such systems do what?", options:["Operate outside governance, lacking the proper security controls and oversight","Always perform far better than any of the officially approved corporate systems","Are automatically covered by the organization's existing cyber insurance policy","Require no electricity or any network connectivity in order to operate effectively"], correct:0, explanation:"Shadow IT lacks governance and controls, raising risk. The other statements are false." },
  { id:40782, domain:4, level:3, question:"A key reason to encrypt data in transit is to achieve what?", options:["Reduce the physical length of the network cabling required between two buildings","Prevent interception and disclosure of data as it crosses the untrusted networks","Guarantee that the receiving server always has unlimited available storage space","Ensure that the data is automatically deleted as soon as it is received at the host"], correct:1, explanation:"Encryption in transit prevents interception. It does not shorten cabling, provide storage, or delete data." },
  { id:40783, domain:4, level:1, question:"The PRIMARY purpose of a hash function in integrity checking is to do what?", options:["Encrypt the data so that only the single intended recipient can ever read it later in practice","Compress the data so that it occupies far less storage space on the disk over time","Detect whether data has been altered by comparing the computed hash values together","Permanently prevent the data from ever being copied to another system at any point"], correct:2, explanation:"Hashing detects alteration via value comparison. It does not encrypt, compress, or prevent copying." },
  { id:40784, domain:4, level:2, question:"A man-in-the-middle attack is BEST mitigated by which of the following?", options:["Disabling all logging so the attacker cannot see any of the recorded activity later","Sharing the encryption keys publicly so that everyone can verify the traffic involved","Increasing the screen resolution on the communicating users' connected devices","Using strong encryption together with mutual authentication for the communications"], correct:3, explanation:"Encryption and mutual authentication thwart interception. Disabling logging, public keys, and resolution changes do not." },
  { id:40785, domain:4, level:3, question:"Why is segregation of duties important in IT operations?", options:["It prevents any single person from controlling an entire critical process end to end","It ensures every task is completed by exactly one person in order to save more time","It allows administrators to skip documenting any of their routine daily activities","It guarantees that no system will ever require a software patch at any point in future"], correct:0, explanation:"Segregation of duties prevents unilateral control of a process. The other statements describe poor or unrelated practices." },
  { id:40786, domain:4, level:2, question:"The MAIN benefit of automated configuration management tools is which of the following?", options:["The complete elimination of any need to ever monitor the system performance again","Consistent and repeatable enforcement of approved configurations across the systems","A guarantee that no configuration will ever need to change at any point in the future","The automatic generation of the organization's full annual financial statements"], correct:1, explanation:"Automation enforces consistent configurations. It does not end monitoring, freeze configs, or produce financials." },
  { id:40787, domain:4, level:3, question:"A rollback plan is an important part of change management because it does what?", options:["Ensures that no change will ever be allowed to fail under any condition whatsoever","Removes the need to test the change before it is deployed into production at all","Allows a failed change to be reversed, restoring the prior known-good system state","Permanently prevents users from accessing the system during the change window"], correct:2, explanation:"A rollback plan reverses failed changes to a known-good state. It does not guarantee success, replace testing, or block all access." },
  { id:40788, domain:4, level:1, question:"The GREATEST risk of granting developers standing access to production is which of the following?", options:["Developers will become too skilled and then demand much higher salaries quite soon","Production servers will physically overheat from all of the additional user logins","The organization will run out of available usernames for any future new hires","Unauthorized or untested changes bypassing the controls and harming live systems"], correct:3, explanation:"Standing production access enables uncontrolled changes. The other options are not real risks." },
  { id:40789, domain:4, level:2, question:"Data sovereignty is a risk consideration in cloud computing because of what?", options:["Data may be subject to the laws of the country in which it is physically stored","Cloud data is always immune from every nation's legal jurisdiction entirely","Storing data abroad automatically makes it impossible to ever access it again","International data storage guarantees lower costs in every single situation always"], correct:0, explanation:"Data sovereignty means storage location determines applicable law. The other statements are false." },
  { id:40790, domain:4, level:3, question:"The PRIMARY reason to perform regular vulnerability scanning is to do what?", options:["Increase the network traffic so the bandwidth contract is fully utilized each month","Identify weaknesses so that they can be remediated before they are ever exploited","Provide a reason to purchase additional unrelated software licenses for the company","Generate reports that are simply filed away and then never reviewed by anyone at all"], correct:1, explanation:"Scanning identifies weaknesses for remediation. The other options describe waste or pointless activity." },
  { id:40791, domain:4, level:2, question:"A least functionality configuration principle requires that systems do what?", options:["Enable every available feature so that users always have the maximum possible choice","Disable all of the security logging in order to maximize the raw processing speed","Run only the services and the features that are necessary for their intended purpose","Grant every user local administrator rights on their own assigned workstation device"], correct:2, explanation:"Least functionality reduces attack surface by limiting services. The other options increase risk." },
  { id:40792, domain:4, level:3, question:"The risk of insufficient logging and monitoring is which of the following?", options:["Systems will physically run faster because they store far fewer log files on disk","Users will be unable to ever log in to any application running on the network","Encryption keys will automatically expire before they can be used even once","Security incidents may go undetected and unanswered for long periods of time"], correct:3, explanation:"Without adequate logging, incidents go undetected. The other statements are false." },
  { id:40793, domain:4, level:1, question:"A backup that captures only the data changed since the last backup is called a what?", options:["Incremental backup, which stores only the changes since the most recent prior backup","Full backup, which copies all of the selected data every single time that it runs","Mirror backup, which keeps a constantly identical real-time copy of all of the data in practice","Snapshot backup, which photographs the physical state of the underlying hardware"], correct:0, explanation:"An incremental backup stores changes since the last backup. The other terms describe different backup types." },
  { id:40794, domain:4, level:2, question:"Air-gapped backups reduce the risk of ransomware because they do what?", options:["Are always stored in a brighter and more visible location for much easier access","Are isolated from the network and cannot be reached by malware that is spreading","Automatically pay any ransom demand on behalf of the affected organization at once","Run far faster than online backups because they skip all of the integrity checks"], correct:1, explanation:"Air-gapped backups are network-isolated, resisting ransomware spread. The other statements are false." },
  { id:40795, domain:4, level:3, question:"The PRIMARY purpose of input validation in application security is to do what?", options:["Increase the font size of the text displayed within the application's main window","Reduce the total number of database servers the application needs in order to run","Prevent malformed or malicious input from causing unintended application behavior","Automatically translate the application's interface into many different languages"], correct:2, explanation:"Input validation blocks malicious input like injection. The other options are unrelated." },
  { id:40796, domain:4, level:2, question:"SQL injection is a risk that arises PRIMARILY from which condition?", options:["Storing the database on a physically larger hard drive than is strictly necessary","Using a fast internet connection between the client device and the web server host","Granting users the ability to change their own display theme and color preferences","Improperly validated user input being passed directly into the database queries"], correct:3, explanation:"SQL injection stems from unvalidated input in queries. The other options have no bearing on it." },
  { id:40797, domain:4, level:3, question:"A web application firewall (WAF) PRIMARILY protects against which threats?", options:["Common web-based attacks such as injection and cross-site scripting against the app","Physical theft of the laptops used by the web development team members at the office","Power outages affecting the building where the web servers are physically hosted","Errors in the company's quarterly financial accounting spreadsheets and reports"], correct:0, explanation:"A WAF filters web attacks like injection and XSS. It does not address theft, power, or accounting." },
  { id:40798, domain:4, level:1, question:"Why is it risky to hard-code credentials in application source code?", options:["Hard-coded credentials make the whole application run noticeably more slowly later in practice","Anyone who accesses the source code can obtain the credentials and then misuse them","Source code physically cannot store any text longer than ten characters in length","Credentials in code are automatically encrypted and so can never be read by anyone"], correct:1, explanation:"Hard-coded credentials are exposed to anyone reading the code. The other statements are false." },
  { id:40799, domain:4, level:2, question:"The risk of using default vendor passwords is that they do what?", options:["Are always far longer and much stronger than any user-chosen password could be","Automatically change themselves every hour without any action from the user at all","Are widely known and easily exploited by attackers to gain unauthorized access","Can only be entered from the physical console and never over a remote network"], correct:2, explanation:"Default passwords are publicly known and easily abused. The other statements are false." },
  { id:40800, domain:4, level:3, question:"A secure software development practice that reduces risk is which of the following?", options:["Deploying every build directly to production without any review or testing at all","Allowing any developer to push changes without ever using any version control","Disabling all automated tests to make the build process complete much faster","Conducting structured code reviews to catch security flaws before any release"], correct:3, explanation:"Code reviews catch flaws early. The other options remove safeguards and increase risk." },
  { id:40801, domain:4, level:2, question:"The PRIMARY risk addressed by certificate management is which of the following?", options:["Expired or invalid certificates causing outages or weakening the established trust","The certificates consuming an excessive amount of physical filing cabinet space","Users being unable to choose their own preferred personal web browser software","The organization running out of available colors for its corporate website design in practice"], correct:0, explanation:"Certificate management prevents expiry-related outages and trust issues. The other options are irrelevant." },
  { id:40802, domain:4, level:3, question:"Why should test data not include real production personal data?", options:["Test environments always run faster when they contain no actual data at all in them","It risks exposing the sensitive personal information within less-protected environments","Real data is physically far too large to ever fit within any test environment at all in practice","Production data automatically corrupts itself whenever it is copied to test systems"], correct:1, explanation:"Using real personal data in test risks exposure. The other statements are false." },
  { id:40803, domain:4, level:1, question:"Containerization technology such as Docker introduces which risk consideration?", options:["Containers each require their own separate physical building in order to operate","Containers can never be scanned for vulnerabilities by any available security tool","A vulnerable shared host kernel could affect multiple running containers at once","Containers automatically eliminate all of the application security requirements"], correct:2, explanation:"Containers share the host kernel, so a kernel flaw affects many. The other statements are false." },
  { id:40804, domain:4, level:2, question:"A key risk of bring-your-own-device (BYOD) programs is which of the following?", options:["A guaranteed reduction in the company's total annual electricity bill every year","The automatic encryption of every personal photo stored on each user's mobile phone in practice","The complete elimination of any need for mobile device management tools at all","Reduced control over device security, which increases the exposure of corporate data"], correct:3, explanation:"BYOD reduces device control, raising data exposure. The other statements are false." },
  { id:40805, domain:4, level:3, question:"Mobile device management (MDM) helps reduce risk by doing what?", options:["Enforcing security policies such as encryption and remote wipe on the managed devices","Increasing the resale value of each individual employee's personal mobile phone unit in practice","Guaranteeing that no employee will ever lose their assigned mobile device ever again","Providing free unlimited cellular data to every enrolled mobile device every month"], correct:0, explanation:"MDM enforces device security policies. It does not affect resale value, prevent loss, or provide data plans." },
  { id:40806, domain:4, level:2, question:"The PRIMARY purpose of a data flow diagram in risk analysis is to do what?", options:["Calculate the exact electricity cost of running each individual server every month","Show how data moves between systems in order to identify the exposure points","List the personal hobbies of each member of the application development team","Determine the optimal paint color for the interior walls of the main data center"], correct:1, explanation:"A data flow diagram reveals where data is exposed. The other options are irrelevant." },
  { id:40807, domain:4, level:3, question:"Why is patch testing especially important for operational technology (OT) systems?", options:["OT systems are always immune to every known software vulnerability by their design","OT systems automatically reject any patch that could possibly cause a problem later","Patches may disrupt critical processes that cannot tolerate any unplanned downtime","Patches for OT systems are guaranteed never to change any behavior whatsoever"], correct:2, explanation:"OT systems run critical processes sensitive to disruption, so patches need careful testing. The other statements are false." },
  { id:40808, domain:4, level:1, question:"A risk practitioner finds that backups are never tested for restorability. The GREATEST concern is what?", options:["The backups occupy storage that could otherwise be used for some other purposes in practice","Testing the backups would require hiring several additional new employees soon","Untested backups always run faster than backups that have been properly tested","Backups may be unusable exactly when they are needed, defeating their core purpose"], correct:3, explanation:"Untested backups may fail to restore when needed. The other concerns are minor or false." },
  { id:40809, domain:4, level:2, question:"The concept of fail securely means that when a system fails it should do what?", options:["Default to a secure state that denies access rather than granting it automatically","Default to granting all of the users full access in order to keep operations running","Display all of the stored data on the screen so administrators can review it easily","Immediately broadcast all of the stored passwords to every currently connected user"], correct:0, explanation:"Fail securely means defaulting to deny on failure. Granting access or leaking data violates the principle." },
  { id:40810, domain:4, level:3, question:"A risk of excessive administrative privileges is which of the following?", options:["Privileged accounts always use weaker passwords than the standard user accounts do","A compromised privileged account grants attackers broad control of the systems","Administrators are legally prohibited from ever logging out of the systems they use","Privileged accounts consume far more network bandwidth than the normal accounts do"], correct:1, explanation:"Excessive privileges magnify the impact of a compromise. The other statements are false." },
  { id:40811, domain:4, level:2, question:"Time synchronization across systems (e.g., via NTP) supports risk management by doing what?", options:["Increasing the clock speed of each server's central processing unit during peak hours","Reducing the physical temperature of the equipment located in the main server room","Ensuring log timestamps align so that events can be correlated together accurately","Guaranteeing that no two systems will ever process any data at exactly the same time"], correct:2, explanation:"Synchronized time enables accurate log correlation. The other options are unrelated." },
  { id:40812, domain:4, level:3, question:"The PRIMARY risk of unencrypted wireless networks is which of the following?", options:["Wireless signals physically damage the devices that happen to receive them nearby","Unencrypted networks are always slower than wired connections in every situation","Wireless devices automatically refuse to connect when there is no encryption at all","Traffic can be intercepted by anyone who is within range of the wireless signal"], correct:3, explanation:"Unencrypted wireless traffic can be intercepted within range. The other statements are false." },
  { id:40813, domain:4, level:1, question:"Why should default guest accounts typically be disabled on systems?", options:["They can provide unauthorized and often anonymous access to the systems involved","Guest accounts always consume the majority of a given server's available memory","Guest accounts automatically gain full administrator rights after one full day passes","Disabling guest accounts is required in order to physically power on the server unit"], correct:0, explanation:"Guest accounts can enable unauthorized anonymous access. The other statements are false." },
  { id:40814, domain:4, level:2, question:"A risk-based approach to access provisioning means access is granted based on what?", options:["The seniority of the requester regardless of any actual job-related need for access","The business need and the sensitivity of the resources that are being accessed","Whichever access request happens to arrive first in the support ticket queue daily","The personal friendship between the requester and the system administrator involved"], correct:1, explanation:"Risk-based provisioning ties access to need and sensitivity. The other options ignore actual need." },
  { id:40815, domain:4, level:3, question:"The GREATEST risk of poorly managed encryption keys is which of the following?", options:["The keys requiring a slightly larger amount of disk storage space on the server","The keys causing the encryption process to be displayed in a different screen font","Loss or compromise of the keys, rendering the data either inaccessible or exposed","The keys preventing the organization from buying any new hardware in the future"], correct:2, explanation:"Mismanaged keys can make data inaccessible or exposed. The other options are trivial or false." },
  { id:40816, domain:4, level:2, question:"Why is it important to remove or disable unused network services on a server?", options:["Unused services automatically share their passwords with all of the system users","Running fewer services prevents the server from ever being backed up correctly","Disabling services is the only way to physically clean the server cooling fans","Each running service expands the overall attack surface available to attackers"], correct:3, explanation:"Unused services expand attack surface and should be removed. The other statements are false." },
  { id:40817, domain:4, level:3, question:"A golden image (standard secure build) reduces risk by doing what?", options:["Ensuring new systems start from a known, hardened, and consistent secure baseline","Guaranteeing that the systems will never need any future updates at any point ahead","Making every system run at exactly the same processor clock frequency continuously","Eliminating the need to ever monitor the systems once they have been deployed live"], correct:0, explanation:"A golden image provides a hardened, consistent baseline. The other statements are false." },
  { id:40818, domain:4, level:1, question:"The PRIMARY risk of allowing weak password policies is which of the following?", options:["Strong passwords physically damage the keyboard keys over an extended time period","Accounts become much easier for attackers to guess or to brute-force successfully","Weak passwords automatically expire much faster than strong passwords ever do","Password length has no effect whatsoever on the actual security of any account"], correct:1, explanation:"Weak password policies ease guessing and brute-forcing. The other statements are false." },
  { id:40819, domain:4, level:2, question:"Account lockout after repeated failed logins MAINLY mitigates which threat?", options:["Phishing emails that ask users to reveal their own passwords entirely willingly","Physical theft of the servers from within the locked and secured data center room","Brute-force password guessing attacks that target the various user accounts","Power surges that could potentially damage the network switching equipment used"], correct:2, explanation:"Lockout thwarts brute-force guessing. It does not stop phishing, theft, or power surges." },
  { id:40820, domain:4, level:3, question:"The risk of storing sensitive data in application logs is which of the following?", options:["Logs automatically encrypt any of the sensitive data that is ever written into them","Sensitive data in logs makes the entire application impossible to ever start up again","Logs can only ever store numbers and never any textual information of any kind at all","Logs may be less protected, thereby exposing the sensitive data that they contain"], correct:3, explanation:"Sensitive data in logs may be exposed due to weaker protection. The other statements are false." },
  { id:40821, domain:4, level:2, question:"A recovery strategy in business continuity defines which of the following?", options:["How the critical functions will be restored within their required timeframes","The marketing campaign used to attract new customers right after an outage ends","The exact paint scheme to be used whenever rebuilding an office building later on","The personal vacation schedule of each member of the senior executive team"], correct:0, explanation:"A recovery strategy defines how to restore critical functions in time. The other options are unrelated." },
  { id:40822, domain:4, level:3, question:"Why are tabletop exercises valuable for continuity planning?", options:["They permanently prevent any real disaster from ever occurring at the site again","They let teams walk through response scenarios and find gaps without any disruption","They are required before a server is ever allowed to be powered on for the first time","They replace the need to maintain any written continuity plan documentation at all"], correct:1, explanation:"Tabletop exercises surface gaps safely. They do not prevent disasters or replace written plans." },
  { id:40823, domain:4, level:1, question:"The risk of relying on a single internet service provider with no redundancy is what?", options:["The provider will automatically double the organization's available bandwidth soon","A single provider is legally prohibited in most of the countries around the world","Loss of connectivity if that one single provider experiences an outage of its own","Redundant providers always cause far more outages than a single provider would"], correct:2, explanation:"A single ISP is a single point of failure for connectivity. The other statements are false." },
  { id:40824, domain:4, level:2, question:"Geographic separation of a recovery site from the primary site reduces the risk of what?", options:["The recovery site receiving a much slower postal mail delivery service each day in practice","Employees having to learn a completely second language in order to use the site","The recovery site automatically increasing the latency of every connection made","A single regional event disabling both of the sites at the very same time at once"], correct:3, explanation:"Geographic separation protects against regional disasters affecting both sites. The other options are irrelevant." },
  { id:40825, domain:4, level:3, question:"The PRIMARY purpose of redundancy such as RAID or clustering is to do what?", options:["Maintain availability by tolerating the failure of individual hardware components","Reduce the purchase price of the underlying server hardware components used overall","Guarantee that data can never be accidentally deleted by any user at any time at all","Eliminate the need to ever perform any backups of the important data at any point"], correct:0, explanation:"Redundancy maintains availability despite component failure. It does not lower cost, prevent deletion, or replace backups." },
  { id:40826, domain:4, level:2, question:"A load balancer contributes to risk reduction MAINLY by doing what?", options:["Encrypting every single email that is sent by the employees within the organization in practice","Distributing the incoming traffic to maintain availability if one server should fail","Physically cooling the servers in order to prevent them from ever overheating badly","Reducing the total number of users who are permitted to access a given service"], correct:1, explanation:"Load balancing maintains availability across servers. It does not encrypt email, cool servers, or limit users." },
  { id:40827, domain:4, level:3, question:"Why is it risky to expose management interfaces such as admin consoles to the internet?", options:["Internet exposure automatically encrypts all of the management interface traffic","Management interfaces work only when reachable from the public internet directly","They become high-value targets for attackers who are seeking privileged system access","Exposing them is the only way to apply any security patches to the underlying system in practice"], correct:2, explanation:"Internet-exposed admin interfaces are prime targets. The other statements are false." },
  { id:40828, domain:4, level:1, question:"The concept of immutable infrastructure reduces risk by doing what?", options:["Ensuring that the infrastructure can never be backed up or restored at all later","Guaranteeing that the infrastructure will never require any security at any time","Allowing any user to modify the production servers without any oversight at all","Replacing rather than modifying systems, which reduces drift and unknown states"], correct:3, explanation:"Immutable infrastructure replaces rather than mutates, reducing drift. The other statements are false." },
  { id:40829, domain:4, level:2, question:"A risk of insufficient separation between development and production environments is what?", options:["Untested or unstable code may inadvertently affect the live production operations","Developers will be completely unable to ever write any new application code at all","Production data will automatically copy itself into the version control repository","The two separate environments will physically merge into a single computer system"], correct:0, explanation:"Poor separation lets unstable code reach production. The other statements are false." },
  { id:40830, domain:4, level:3, question:"The PRIMARY benefit of infrastructure-as-code (IaC) for risk management is which of these?", options:["The complete removal of any need to ever secure the provisioned resources at all","Consistent, version-controlled, and auditable provisioning of the cloud resources","A guarantee that the cloud costs will be exactly zero for the whole organization","The automatic hiring of additional staff to manage the new provisioned infrastructure"], correct:1, explanation:"IaC provides consistent, auditable provisioning. It does not remove security needs, zero out costs, or hire staff." },
  { id:40831, domain:4, level:2, question:"Why should privileged sessions be recorded for risk management purposes?", options:["To increase the available storage space on the privileged user's personal laptop","To allow the privileged user to replay videos for their own personal entertainment","To support accountability and investigation of actions taken with the high access","To replace the need for the user to authenticate before each new session begins"], correct:2, explanation:"Recording privileged sessions supports accountability and investigation. The other options are false." },
  { id:40832, domain:4, level:3, question:"A risk of relying solely on perimeter security is which of the following?", options:["Perimeter security physically prevents the employees from ever leaving the office","A perimeter firewall automatically patches every internal server each and every day","Perimeter controls make any form of internal encryption completely unnecessary","Once the perimeter is breached, the internal systems may be very poorly protected"], correct:3, explanation:"Sole reliance on the perimeter leaves the interior exposed if breached. The other statements are false." },
  { id:40833, domain:4, level:1, question:"The principle of complete mediation requires which of the following?", options:["Every access to a resource is checked against the authorization rules each time","Access is checked only once and then permanently trusted forever afterward without","Authorization is decided by the very user who is requesting the access themselves","Only the first user of the day needs to be authorized for the entire system at all"], correct:0, explanation:"Complete mediation checks every access each time. The other options describe weaker, riskier approaches." },
  { id:40834, domain:4, level:2, question:"Why is data integrity important for decision-making systems?", options:["Data integrity makes the database files occupy far less storage space on the disk","Inaccurate or altered data can lead to incorrect and potentially harmful decisions","High integrity data automatically runs on faster network connections every time","Integrity controls remove the need to ever back up any of the data at all later on"], correct:1, explanation:"Compromised data integrity yields bad decisions. The other statements are false." },
  { id:40835, domain:4, level:3, question:"A kill switch or emergency shutdown capability supports risk management by doing what?", options:["Permanently preventing the system from ever being powered back on again afterward in practice","Automatically improving the performance of the system during any normal operation","Allowing rapid containment by disabling a compromised system very quickly when needed","Automatically increasing the system's processing speed during any active attack"], correct:2, explanation:"A kill switch enables rapid containment. The other options are false." },
  { id:40836, domain:4, level:2, question:"The risk of unmonitored third-party remote access is which of the following?", options:["Third parties will automatically improve the organization's overall security posture","Remote access by third parties is always encrypted and is therefore never risky","Monitoring third-party access is completely physically impossible in all the cases","External parties could access the systems without any detection or accountability"], correct:3, explanation:"Unmonitored third-party access lacks detection and accountability. The other statements are false." },
  { id:40837, domain:4, level:3, question:"Why is multi-region cloud deployment a risk consideration for an organization?", options:["It improves resilience but adds complexity and potential data residency concerns","It guarantees that the application will be completely free to operate from then on","It removes the need to secure any of the deployed cloud resources in any region","It makes the application physically impossible for any of the users to ever access"], correct:0, explanation:"Multi-region adds resilience but also complexity and residency concerns. The other statements are false." },
  { id:40838, domain:4, level:1, question:"A risk of overly permissive cloud storage permissions such as public buckets is what?", options:["Cloud storage automatically encrypts any of the publicly accessible stored data","Sensitive data could be exposed to literally anyone who is on the public internet","Public storage is always faster and is therefore always the preferable option","Permissive permissions reduce the organization's total cloud storage costs greatly"], correct:1, explanation:"Public buckets can expose sensitive data broadly. The other statements are false." },
  { id:40839, domain:4, level:2, question:"The PRIMARY purpose of egress filtering is to do what?", options:["Increase the inbound bandwidth available to all of the internal applications used","Physically block any visitors from leaving the office building after normal hours","Control and inspect outbound traffic in order to help detect data exfiltration","Encrypt all of the files that are stored on the organization's main file servers"], correct:2, explanation:"Egress filtering controls outbound traffic, helping detect exfiltration. The other options are unrelated." },
  { id:40840, domain:4, level:3, question:"Why should security patches be prioritized by their exploitability and exposure?", options:["Every patch is identical in its risk, so the order never actually matters at all","Patches should always be applied in strict reverse alphabetical order by their name","Only patches that are released on a Monday are ever worth applying to any systems","Resources are limited, so the most dangerous vulnerabilities should be fixed first"], correct:3, explanation:"Prioritizing by exploitability and exposure uses limited resources well. The other statements are false." },
  { id:40841, domain:4, level:2, question:"A risk of disabling automatic updates without an alternative process is which of these?", options:["Critical security patches may be delayed, thereby prolonging the vulnerability exposure","Systems will automatically install all of the updates twice as fast as they did before in practice","Disabling the updates encrypts the system against every kind of possible attack","Manual updates are always applied much faster than the automatic ones ever are"], correct:0, explanation:"Disabling auto-updates without a process delays patches. The other statements are false." },
  { id:40842, domain:4, level:3, question:"The GREATEST risk of an unsegmented flat network is which of the following?", options:["A flat network physically uses much more electrical power than a segmented one","An attacker who breaches one single host can then easily reach all of the others","Flat networks automatically encrypt all of the traffic between every connected device","Flat networks prevent any device from ever being assigned a valid network address"], correct:1, explanation:"A flat network lets a breach spread freely. The other statements are false." },
  { id:40843, domain:4, level:1, question:"Why is endpoint detection and response (EDR) valuable in risk management?", options:["It physically locks the endpoint device inside a secure heavy metal cabinet daily","It guarantees the endpoints will never need any kind of software update ever again","It detects and responds to threats on endpoints that may bypass other controls","It removes the requirement for users to authenticate to their own device at all"], correct:2, explanation:"EDR detects and responds to endpoint threats. The other statements are false." },
  { id:40844, domain:4, level:2, question:"A risk of excessive data retention beyond actual business need is which of the following?", options:["Retained data automatically becomes much more accurate as the years go by over time","Longer retention of data always reduces the organization's total storage costs","Old data physically protects the newer data from ever being compromised at all","More retained data increases the potential exposure and breach impact unnecessarily"], correct:3, explanation:"Excessive retention enlarges the breach blast radius. The other statements are false." },
  { id:40845, domain:4, level:3, question:"Why is secure disposal of decommissioned media important for risk management?", options:["Residual data could be recovered and disclosed if the media is not first sanitized","Decommissioned media automatically erases all of itself the moment it is unplugged","Disposed media that is not sanitized physically improves new equipment performance","Decommissioned media always loses all of its stored data within exactly one hour"], correct:0, explanation:"Improperly disposed media may leak recoverable data. The other statements are false." },
  { id:40846, domain:4, level:2, question:"The PRIMARY risk of using personal email for business data is which of the following?", options:["Personal email accounts always run much faster than the corporate email systems do","Sensitive data leaves the organizational controls and the related monitoring systems","Personal email automatically applies the company's full data encryption policy to it","Business data sent personally is automatically deleted right after it is sent away"], correct:1, explanation:"Personal email moves data outside organizational controls. The other statements are false." },
  { id:40847, domain:4, level:3, question:"A data loss prevention (DLP) system PRIMARILY helps to do what?", options:["Increase the overall speed of the organization's internet connection quite broadly","Physically prevent any laptops from being removed from inside the office building","Detect and prevent the unauthorized transmission of sensitive data outside the org","Generate the company's quarterly profit and loss financial statements each period"], correct:2, explanation:"DLP detects and prevents unauthorized data transmission. The other options are unrelated." },
  { id:40848, domain:4, level:1, question:"Why is a formal offboarding process important for risk management?", options:["It guarantees that departing employees will return all of the office stationery items","It automatically increases the salaries of the remaining employees who stay behind","It physically prevents former employees from entering any of the company buildings","It ensures the departing users' access is promptly revoked to help prevent misuse"], correct:3, explanation:"Offboarding revokes access promptly, preventing misuse. The other statements are false or trivial." },
  { id:40849, domain:4, level:2, question:"The risk of privilege creep over time is that users do what?", options:["Accumulate access rights that they no longer actually need, expanding the exposure","Gradually lose all of their access until they cannot do any of their work at all in practice","Automatically have all of their access removed at the very end of each work week","Are required to re-apply for their entire job role every single working morning"], correct:0, explanation:"Privilege creep accumulates unneeded rights, expanding exposure. The other statements are false." },
  { id:40850, domain:4, level:3, question:"Why is it important to validate the identity of users requesting password resets?", options:["Password resets physically damage the underlying authentication server hardware","Attackers may impersonate users to gain unauthorized access to the target accounts","Validating identity makes the entire reset process take several days much longer in practice","Resets always succeed regardless of who actually requests them in the end anyway"], correct:1, explanation:"Identity validation prevents reset-based account takeover. The other statements are false." },
  { id:40851, domain:4, level:2, question:"A risk of single sign-on (SSO) is which of the following?", options:["SSO requires each user to remember a unique separate password for every system used","SSO physically increases the electricity consumed by every authentication server","Compromise of the SSO credentials can grant access to many systems at the same time","SSO physically prevents users from ever logging in to more than a single system"], correct:2, explanation:"SSO concentrates risk: one credential unlocks many systems. The other statements are false." },
  { id:40852, domain:4, level:3, question:"Why is reviewing firewall rules periodically important for risk management?", options:["Firewall rules expire all on their own and must then be repurchased every month","Reviewing the rules greatly increases the firewall's maximum throughput speed","Firewalls stop functioning entirely if any of their rules are ever once reviewed","Stale or overly permissive rules can create unintended access paths into systems"], correct:3, explanation:"Periodic review removes stale, permissive rules. The other statements are false." },
  { id:40853, domain:4, level:1, question:"The PRIMARY risk of unrestricted USB device use is which of the following?", options:["Introduction of malware or the exfiltration of data via removable storage media","USB devices physically slow down the speed of the computer's internal cooling fan","Unrestricted USB use automatically encrypts all of the connected storage devices","USB ports stop working entirely unless every possible device is fully allowed"], correct:0, explanation:"Unrestricted USB enables malware and exfiltration. The other statements are false." },
  { id:40854, domain:4, level:2, question:"Why should default sample applications be removed from production web servers?", options:["Sample applications consume all of the server's available memory within minutes","They may contain known vulnerabilities that attackers can exploit to gain access","Removing the samples is the only way to physically clean the server's outer case","Sample applications automatically encrypt the entire web server's storage disk"], correct:1, explanation:"Sample apps may harbor exploitable flaws and should be removed. The other statements are false." },
  { id:40855, domain:4, level:3, question:"A risk of inconsistent logging across systems is which of the following?", options:["Consistent logs always run on much faster processors than inconsistent ones do","Inconsistent logging physically reduces the size of the server's hard drives over time","Incident investigators may be unable to reconstruct a complete event timeline later","Logs that differ automatically correct themselves over a short period of time later"], correct:2, explanation:"Inconsistent logging hampers timeline reconstruction. The other statements are false." },
  { id:40856, domain:4, level:2, question:"Why is encryption key rotation a recommended security practice?", options:["Key rotation makes the underlying encryption algorithm run noticeably much faster","Rotating the keys removes the need to ever protect any of the keys themselves at all","New keys are always physically smaller in size than the keys that they replace","It limits the amount of data exposed if a given key is eventually ever compromised"], correct:3, explanation:"Key rotation limits exposure from a compromised key. The other statements are false." },
  { id:40857, domain:4, level:3, question:"The risk of not having a formal incident classification scheme is which of the following?", options:["Incidents may receive inconsistent prioritization and an inconsistent response","Classification schemes physically slow down the entire incident response process","Without any classification scheme, no incidents can ever occur on the network","Classification automatically resolves all of the incidents without any action"], correct:0, explanation:"Without classification, response priority is inconsistent. The other statements are false." },
  { id:40858, domain:4, level:1, question:"Why should an organization define a chain of custody for digital evidence?", options:["To increase the total physical weight of the evidence storage containers used","To preserve the admissibility and integrity of the evidence throughout its handling","To allow any employee to freely alter the evidence at any time they wish to do so","To ensure that the evidence is automatically deleted after exactly one week passes in practice"], correct:1, explanation:"Chain of custody preserves evidence integrity and admissibility. The other statements are false." },
  { id:40859, domain:4, level:2, question:"A risk of failing to monitor cloud service configurations is which of the following?", options:["Cloud configurations automatically correct any mistake on their own within minutes","Unmonitored configurations always cost much less money than monitored ones do","Misconfigurations may expose data or services without ever being noticed in time","Monitoring the configurations physically prevents the servers from ever running"], correct:2, explanation:"Unmonitored cloud configs can expose data unnoticed. The other statements are false." },
  { id:40860, domain:4, level:3, question:"Why is it important to test failover mechanisms regularly?", options:["Testing failover permanently prevents the primary system from ever failing again","Failover testing automatically doubles the total available network bandwidth at once","Untested failover is always far more reliable than any tested failover system is","To confirm that the systems actually switch over correctly during a real failure"], correct:3, explanation:"Failover testing confirms correct switchover when needed. The other statements are false." },
  { id:40861, domain:4, level:2, question:"The risk of using outdated TLS protocol versions is that they do what?", options:["May contain weaknesses that allow attackers to decrypt or tamper with the traffic","Always provide much stronger protection than any newer protocol version available","Physically prevent the web server from accepting any new connections at all ever","Automatically upgrade themselves to the very latest version each time they are used"], correct:0, explanation:"Outdated TLS versions have known weaknesses. The other statements are false." },
  { id:40862, domain:4, level:3, question:"Why is segmentation of payment systems handling cardholder data important?", options:["It guarantees that the payment systems will never need any patching at any point","It limits the scope of systems that are exposed to the sensitive payment information","It physically prevents the payment terminals from ever being moved within a store in practice","It automatically makes the organization fully compliant with all relevant laws"], correct:1, explanation:"Segmenting payment systems limits exposure scope. The other statements are false." },
  { id:40863, domain:4, level:1, question:"A risk of relying on a single administrator with exclusive system knowledge is what?", options:["The administrator will automatically train a full replacement entirely on their own","Single-administrator systems are always much more secure than any shared systems","Operations and recovery may fail entirely if that one person is suddenly unavailable","Exclusive knowledge physically speeds up the recovery of all of the systems involved"], correct:2, explanation:"Single-administrator dependency threatens operations and recovery. The other statements are false." },
  { id:40864, domain:4, level:2, question:"Why is documenting system dependencies important for continuity planning?", options:["Documentation physically prevents any of the systems from ever failing in future","Dependencies will automatically resolve themselves during any real disaster event","Documenting the dependencies removes the need to ever test the continuity plan","Recovery sequencing requires knowing which systems depend on which other systems"], correct:3, explanation:"Dependency documentation guides recovery sequencing. The other statements are false." },
  { id:40865, domain:4, level:3, question:"The PRIMARY risk of an excessively long patch cycle is which of the following?", options:["Vulnerabilities remain exploitable for extended periods before they are finally fixed","Long patch cycles automatically encrypt all of the unpatched systems for safety","Long patch cycles physically reduce the available storage on each affected server in practice","Patches that are applied late are always far more effective than early ones are"], correct:0, explanation:"Long patch cycles prolong exploitability. The other statements are false." },
  { id:40866, domain:4, level:2, question:"Why should remote administration use encrypted protocols such as SSH instead of Telnet?", options:["Encrypted protocols physically use much thicker network cables in order to operate","Unencrypted protocols expose the credentials and the commands to interception","Telnet is always faster and is therefore always the much safer choice to use here","Encryption removes the need to authenticate before ever administering any host"], correct:1, explanation:"Encrypted remote admin protects credentials from interception. The other statements are false." },
  { id:40867, domain:4, level:3, question:"A risk of granting third-party vendors broad standing network access is which of these?", options:["Vendors will automatically improve the network's overall performance over time","Broad vendor access is always required by every single security framework that exists","A compromise of the vendor could give attackers broad access to your own network","Standing access physically prevents the vendor itself from ever being compromised"], correct:2, explanation:"Broad vendor access widens the attack path if the vendor is compromised. The other statements are false." },
  { id:40868, domain:4, level:1, question:"Why is it important to maintain an up-to-date network diagram?", options:["An up-to-date diagram automatically blocks all of the malicious traffic on its own","Network diagrams physically increase the speed of all of the network connections","Maintaining a diagram removes the need to ever secure any of the network devices","It supports accurate risk assessment, troubleshooting, and incident response work"], correct:3, explanation:"Current network diagrams support risk assessment and response. The other statements are false." },
  { id:40869, domain:4, level:2, question:"The risk of allowing split tunneling on VPN connections is which of the following?", options:["Traffic may bypass corporate inspection, thereby increasing the exposure to threats","Split tunneling physically severs the user's primary internet connection entirely","Split tunneling makes the VPN connection run far faster than it otherwise would","Split tunneling automatically encrypts all of the user's local files on the device in practice"], correct:0, explanation:"Split tunneling can route traffic around inspection, raising risk. The other statements are false." },
  { id:40870, domain:4, level:3, question:"Why is it risky to store backups in the same physical location as primary data?", options:["Co-located backups are always far slower to restore than any remote backups would be","A single disaster could destroy both the primary data and all of its backups at once","Storing the backups together always uses far more electricity than separate storage","Storing backups together automatically corrupts the primary data over a short time"], correct:1, explanation:"Co-located backups can be lost in the same disaster as primary data. The other statements are false." },
  { id:40871, domain:4, level:2, question:"A risk of insufficient bandwidth at a recovery site is which of the following?", options:["The recovery site will automatically generate additional bandwidth when it is needed in practice","Insufficient bandwidth physically prevents any disaster from ever occurring at all","Critical operations may not perform adequately after the failover to that site occurs","Low bandwidth at the site always makes the recovery process complete much faster"], correct:2, explanation:"Inadequate recovery-site bandwidth degrades post-failover operations. The other statements are false." },
  { id:40872, domain:4, level:3, question:"Why is asset criticality classification a prerequisite for prioritizing controls?", options:["Every asset is exactly equally critical, so any classification is never ever needed","Classification physically increases the monetary value of each asset that is listed","Critical assets automatically protect themselves without any controls at all needed","Limited resources should protect the most business-critical assets ahead of others"], correct:3, explanation:"Criticality classification directs limited resources to top assets. The other statements are false." },
  { id:40873, domain:4, level:1, question:"The risk of unvalidated file uploads in a web application is which of the following?", options:["Malicious files could be uploaded and then executed to compromise the host server","File uploads always run much faster when they are never validated by the app at all","Validation physically prevents users from ever uploading any file to the server","Unvalidated uploads automatically encrypt the entire web server's storage disk"], correct:0, explanation:"Unvalidated uploads can lead to malicious file execution. The other statements are false." },
  { id:40874, domain:4, level:2, question:"Why should application error messages avoid revealing detailed system information?", options:["Detailed error messages physically slow down the application's overall response time","Detailed errors can give attackers information that is useful for crafting attacks","Verbose errors automatically encrypt the underlying application database tables","Hiding errors prevents the application from ever functioning correctly for users"], correct:1, explanation:"Verbose errors leak information useful to attackers. The other statements are false." },
  { id:40875, domain:4, level:3, question:"A risk of not enforcing session timeouts in applications is which of the following?", options:["Session timeouts physically damage the user's installed web browser software soon in practice","Without timeouts, the user sessions automatically encrypt all of themselves fully","Unattended authenticated sessions could be hijacked or otherwise misused by others","Sessions that never expire are always far more secure than ones that do expire"], correct:2, explanation:"No session timeout leaves sessions open to hijacking or misuse. The other statements are false." },
  { id:40876, domain:4, level:2, question:"Why is cross-site scripting (XSS) considered a security risk?", options:["XSS physically overheats the web server's central processing unit during an attack in practice","XSS automatically improves the visual appearance of the affected target web page","XSS can only ever affect the attacker's own computer and never anyone else at all","It allows attackers to inject scripts that then run within other users' web browsers"], correct:3, explanation:"XSS injects scripts that execute in victims' browsers. The other statements are false." },
  { id:40877, domain:4, level:1, question:"The PRIMARY risk of insecure direct object references is which of the following?", options:["Users may access data or functions that they are not actually authorized to use","Direct references physically increase the database server's overall speed greatly","Insecure references always make the application impossible to ever compile fully","Insecure references automatically encrypt all of the referenced data objects"], correct:0, explanation:"Insecure direct object references allow unauthorized access. The other statements are false." },
  { id:40878, domain:4, level:2, question:"Why is rate limiting useful for application security?", options:["Rate limiting physically increases the total number of available application servers","It helps mitigate brute-force and denial-of-service attempts against the service","It guarantees that the application will never receive any incoming traffic at all","Rate limiting automatically resolves all known application vulnerabilities at once"], correct:1, explanation:"Rate limiting curbs brute-force and DoS attempts. The other statements are false." },
  { id:40879, domain:4, level:2, question:"A risk of relying on security through obscurity alone is which of the following?", options:["Obscurity physically prevents the attackers from ever finding the office building","Hidden systems automatically encrypt all of their own stored data without any keys","Once the hidden details are discovered, no real protection remains for the system","Security through obscurity always exceeds the strength of any other control type"], correct:2, explanation:"Obscurity alone fails once details are discovered. The other statements are false." },
  { id:40880, domain:4, level:1, question:"Why is it important to harden default operating system installations?", options:["Hardening physically reduces the total size of the computer's installed hard drive","Default installations are always far more secure than any hardened build could be","Hardening an operating system removes the need to ever apply security patches later","Default settings often enable unnecessary and insecure services and user accounts"], correct:3, explanation:"Default OS installs often include insecure defaults that hardening removes. The other statements are false." },
  { id:40881, domain:4, level:2, question:"The risk of not monitoring privileged account creation is which of the following?", options:["Unauthorized privileged accounts could be created and then used entirely undetected","Privileged accounts automatically delete themselves right after they are created in practice","Monitoring account creation physically prevents any new account from being made","Monitoring account creation physically slows down the entire corporate network"], correct:0, explanation:"Unmonitored privileged account creation enables stealthy backdoors. The other statements are false." },
  { id:40882, domain:4, level:2, question:"Why is it risky to reuse the same credentials across multiple systems?", options:["Reused credentials are always longer and much stronger than any unique credentials","Compromise of one system exposes every other system sharing those same credentials","Reusing the credentials physically reduces the load placed on the login server","Shared credentials automatically rotate themselves on every single user login"], correct:1, explanation:"Credential reuse means one breach unlocks many systems. The other statements are false." },
  { id:40883, domain:4, level:1, question:"A risk of inadequate change documentation is which of the following?", options:["Undocumented changes always perform much better than any documented changes do","Documentation physically prevents any change from ever failing in the future at all","Difficulty diagnosing issues and reversing the changes whenever problems arise","Lack of documentation automatically speeds up the entire incident resolution process"], correct:2, explanation:"Poor change documentation hampers diagnosis and rollback. The other statements are false." },
  { id:40884, domain:4, level:2, question:"Why should organizations classify incidents by their severity level?", options:["Severity classification physically prevents the incidents from spreading further","Severity classification always makes every incident automatically resolve itself","All incidents have identical impact, so severity classification never matters at all","To allocate the response resources appropriately based on the potential impact"], correct:3, explanation:"Severity classification directs response resources by impact. The other statements are false." },
  { id:40885, domain:4, level:2, question:"The risk of unpatched network devices such as routers and switches is which of these?", options:["They can be compromised to intercept, redirect, or otherwise disrupt the traffic","Network devices are completely immune to all software vulnerabilities by design","Unpatched devices automatically run much faster than fully patched devices do","Patching any network device physically disconnects it from the network permanently"], correct:0, explanation:"Unpatched network devices can be compromised to manipulate traffic. The other statements are false." },
  { id:40886, domain:4, level:1, question:"Why is anomaly-based detection valuable alongside signature-based detection?", options:["Anomaly detection physically blocks the electrical power to the malicious servers","It can detect novel threats that do not yet have any known signature available","Signature detection alone already catches every possible threat in existence","Anomaly detection removes the need to ever update any of the security software"], correct:1, explanation:"Anomaly detection finds novel, signatureless threats. The other statements are false." },
  { id:40887, domain:4, level:2, question:"A risk of overprivileged service accounts is which of the following?", options:["Service accounts physically cannot ever be compromised by any attacker at all","Overprivileged accounts always automatically use much stronger passwords by default","Their compromise can give attackers broad and often unmonitored system access","Service accounts never require any monitoring at all because they are fully automated"], correct:2, explanation:"Overprivileged service accounts widen the impact of compromise. The other statements are false." },
  { id:40888, domain:4, level:2, question:"Why is it important to validate restored data after a recovery operation?", options:["Validation physically increases the overall speed of the entire recovery process","Restored data is always automatically correct and so it never needs any checking","Validating the data removes the need to have performed any backup at all earlier","To confirm the data is complete and accurate before resuming normal operations"], correct:3, explanation:"Validating restored data confirms completeness and accuracy. The other statements are false." },
  { id:40889, domain:4, level:1, question:"The risk of not defining clear data ownership is which of the following?", options:["Accountability for protecting and classifying the data becomes unclear over time","Data that has no owner will automatically encrypt itself for added safety","Undefined ownership physically prevents the data from ever being stored at all in practice","Data ownership has no effect on how the underlying data is actually protected"], correct:0, explanation:"Undefined data ownership blurs protection accountability. The other statements are false." },
  { id:40890, domain:4, level:2, question:"Why should mobile devices used for work support a remote wipe capability?", options:["Remote wipe physically returns the device automatically to the original manufacturer","Lost or stolen devices can be cleared to prevent the disclosure of the data on them","Remote wipe significantly increases the battery life of the mobile device over time","Devices with remote wipe never need any passcode protection of any kind at all"], correct:1, explanation:"Remote wipe clears data from lost or stolen devices. The other statements are false." },
  { id:40891, domain:4, level:2, question:"A risk of inconsistent encryption standards across an organization is which of these?", options:["Consistent standards physically slow down every single encrypted system that exists","Inconsistent encryption always provides much stronger overall protection of data","Some sensitive data may be protected weakly or perhaps not be protected at all","Encryption standards have no real effect on the actual security of any of the data"], correct:2, explanation:"Inconsistent standards can leave some data weakly protected. The other statements are false." },
  { id:40892, domain:4, level:2, question:"Why is network traffic monitoring useful for risk management?", options:["Monitoring physically increases the available bandwidth of every connection used","Traffic monitoring guarantees that no attack can ever succeed against the network","Monitoring removes the need to apply any security patches to the network devices","It helps detect anomalies, intrusions, and potential data exfiltration attempts"], correct:3, explanation:"Traffic monitoring detects anomalies and exfiltration. The other statements are false." },
  { id:40893, domain:4, level:2, question:"The risk of allowing unsigned code execution on systems is which of the following?", options:["Malicious or tampered code may run without any verification of its actual source","Unsigned code always runs much faster than any digitally signed code ever does","Unsigned code physically prevents the operating system from starting up correctly","Signing the code physically prevents the code from ever being executed at all"], correct:0, explanation:"Allowing unsigned code permits unverified, possibly malicious code. The other statements are false." },
  { id:40894, domain:4, level:2, question:"Why should backup media be encrypted as a standard practice?", options:["Encrypted backups physically weigh much less than any unencrypted backups do","Lost or stolen media would not expose any readable data if it has been encrypted","Encryption makes the entire backup process complete in half of the usual time","Encrypted media can never be restored under any circumstances at all ever again in practice"], correct:1, explanation:"Encrypting backup media protects data if media is lost or stolen. The other statements are false." },
  { id:40895, domain:4, level:2, question:"A risk of not segregating duties in financial systems is which of the following?", options:["Segregation physically slows down every single financial transaction that is made","Without segregation, the transactions automatically become much more accurate","One single person could both initiate and then conceal fraudulent transactions","Duties have no real effect on the risk of fraud within the financial systems"], correct:2, explanation:"Without segregation, one person can commit and hide fraud. The other statements are false." },
  { id:40896, domain:4, level:2, question:"Why is it important to monitor for unauthorized configuration changes on systems?", options:["Configuration changes physically cannot affect any system's security in any way","Monitoring the changes greatly increases the storage space available on the server","Unauthorized changes always improve the affected system's performance levels","They may indicate an active attack or introduce new vulnerabilities into systems"], correct:3, explanation:"Unauthorized config changes may signal attack or add weaknesses. The other statements are false." },
  { id:40897, domain:4, level:2, question:"The PRIMARY risk of poor capacity planning for storage is which of the following?", options:["Systems may fail or lose data when the storage is unexpectedly fully exhausted","Extra storage capacity physically improves the confidentiality of the stored data","Storage capacity has no real relationship to the overall system availability at all","Poor planning always reduces the total cost of the storage hardware significantly"], correct:0, explanation:"Poor storage capacity planning risks failures and data loss. The other statements are false." },
  { id:40898, domain:4, level:2, question:"Why is identity federation a risk consideration for connected organizations?", options:["Federation physically prevents any of the users from ever logging in at all again","Trust between organizations means a partner's compromise can directly affect you","Federated identities are always entirely immune to every form of compromise","Federation removes the need to authenticate any of the users across the systems"], correct:1, explanation:"Federation extends trust, so a partner's compromise can affect you. The other statements are false." },
  { id:40899, domain:4, level:2, question:"A risk of not testing application code for security flaws is which of the following?", options:["Untested code always performs much faster than tested code does in production use","Testing the code physically prevents it from ever being deployed to a live server","Exploitable vulnerabilities may reach the production environment fully undetected","Code without any testing automatically becomes free of all possible vulnerabilities"], correct:2, explanation:"Untested code may ship exploitable flaws. The other statements are false." },
  { id:40900, domain:4, level:2, question:"Why is it important to limit the blast radius of cloud credentials?", options:["Scoped credentials physically run on separate dedicated electrical power circuits","Scoped credentials always make the cloud workloads run noticeably much faster","Broad credentials are always far more secure than any narrowly scoped credentials","Compromise of scoped credentials affects far fewer resources than broad ones do"], correct:3, explanation:"Limiting credential scope reduces compromise impact. The other statements are false." },
];
